import React, { useCallback, useEffect, useMemo, useState } from 'react';
import './App.css';

const API_BASE = '/api/v1';

const initialRegister = {
  email: '',
  phone: '',
  username: '',
  password: '',
  role: 'DONOR',
};

const initialLogin = {
  email: '',
  password: '',
};

const initialDonor = {
  can_donate_blood: true,
  organ_types: 'KIDNEY',
  organ_donation_registered: true,
  preferred_donation_time: 'MORNING',
  profile: {
    first_name: '',
    last_name: '',
    date_of_birth: '1990-01-01',
    gender: 'OTHER',
    address: '',
    city: '',
    state: '',
    postal_code: '',
    country: 'India',
    latitude: '19.0760',
    longitude: '72.8777',
    blood_group: 'O+',
    emergency_contact_name: '',
    emergency_contact_phone: '',
  },
};

const initialRecipient = {
  primary_disease: '',
  diagnosis_date: '2024-01-01',
  surgery_needed_date: '2026-05-01',
  hospital_name: '',
  hospital_contact_phone: '',
  doctor_name: '',
  doctor_phone: '',
  doctor_registration_number: '',
  matching_criteria: {
    urgency: 'CRITICAL',
  },
  profile: {
    first_name: '',
    last_name: '',
    date_of_birth: '1995-01-01',
    gender: 'OTHER',
    address: '',
    city: '',
    state: '',
    postal_code: '',
    country: 'India',
    latitude: '19.0596',
    longitude: '72.8295',
    blood_group: 'AB+',
    emergency_contact_name: '',
    emergency_contact_phone: '',
  },
};

const initialRequest = {
  request_type: 'BLOOD',
  blood_group_needed: 'AB+',
  organ_type_needed: 'KIDNEY',
  quantity_needed: '1',
  urgency_level: 'CRITICAL',
  needed_by: '',
  hospital_name: '',
  receiving_doctor_name: '',
  receiving_doctor_phone: '',
  hospital_location: {
    latitude: '19.0596',
    longitude: '72.8295',
    address: '',
  },
  clinical_notes: '',
  required_tests: 'CBC',
  is_public: true,
};

function App() {
  const [backendStatus, setBackendStatus] = useState('Checking backend...');
  const [authMode, setAuthMode] = useState('login');
  const [registerForm, setRegisterForm] = useState(initialRegister);
  const [loginForm, setLoginForm] = useState(initialLogin);
  const [otpState, setOtpState] = useState({ email: '', phone: '', emailOtp: '', phoneOtp: '' });
  const [auth, setAuth] = useState(() => {
    const raw = localStorage.getItem('donation_auth');
    return raw ? JSON.parse(raw) : null;
  });

  const [flash, setFlash] = useState({ type: 'info', text: 'Start by signing in or creating an account.' });
  const [activeTab, setActiveTab] = useState('dashboard');

  const [donorForm, setDonorForm] = useState(initialDonor);
  const [recipientForm, setRecipientForm] = useState(initialRecipient);
  const [requestForm, setRequestForm] = useState(initialRequest);

  const [requests, setRequests] = useState([]);
  const [matches, setMatches] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [liveEvents, setLiveEvents] = useState([]);
  const [users, setUsers] = useState([]);
  const [analytics, setAnalytics] = useState(null);

  const role = auth?.user?.role || '';

  const wsUrl = useMemo(() => {
    return `ws://localhost:8002/api/v1/ws/notifications?token=${auth?.token || ''}`;
  }, [auth]);

  useEffect(() => {
    fetch('/health')
      .then((res) => res.json())
      .then(() => setBackendStatus('Backend connected'))
      .catch(() => setBackendStatus('Backend not reachable'));
  }, []);

  useEffect(() => {
    if (auth) {
      localStorage.setItem('donation_auth', JSON.stringify(auth));
    } else {
      localStorage.removeItem('donation_auth');
    }
  }, [auth]);

  async function apiRequest(path, options = {}) {
    const headers = {
      'Content-Type': 'application/json',
      ...(options.token ? { Authorization: `Bearer ${options.token}` } : {}),
    };

    const response = await fetch(`${API_BASE}${path}`, {
      method: options.method || 'GET',
      headers,
      body: options.body ? JSON.stringify(options.body) : undefined,
    });

    const contentType = response.headers.get('content-type') || '';
    const payload = contentType.includes('application/json') ? await response.json() : null;

    if (!response.ok) {
      const message = payload?.error?.message || payload?.detail || 'Request failed';
      throw new Error(message);
    }
    return payload;
  }

  async function handleRegister(event) {
    event.preventDefault();
    try {
      const data = await apiRequest('/auth/register', {
        method: 'POST',
        body: registerForm,
      });

      setAuth({
        token: data.tokens.access_token,
        refreshToken: data.tokens.refresh_token,
        user: data.user,
      });

      setOtpState({
        email: registerForm.email,
        phone: registerForm.phone,
        emailOtp: data.otp_preview?.email_otp || '',
        phoneOtp: data.otp_preview?.phone_otp || '',
      });

      setFlash({
        type: 'success',
        text: 'Registered. Verify email and phone to complete setup.',
      });

      setActiveTab('verify');
      setRegisterForm(initialRegister);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function handleLogin(event) {
    event.preventDefault();
    try {
      const data = await apiRequest('/auth/login', {
        method: 'POST',
        body: loginForm,
      });
      setAuth({
        token: data.tokens.access_token,
        refreshToken: data.tokens.refresh_token,
        user: data.user,
      });
      setFlash({ type: 'success', text: 'Login successful.' });
      setActiveTab('dashboard');
      setLoginForm(initialLogin);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function verifyContact(channel) {
    try {
      if (!otpState.email || !otpState.phone) {
        throw new Error('Register first to receive OTP values.');
      }

      if (channel === 'email') {
        await apiRequest('/auth/verify-email', {
          method: 'POST',
          body: { email: otpState.email, otp: otpState.emailOtp },
        });
      } else {
        await apiRequest('/auth/verify-phone', {
          method: 'POST',
          body: { phone: otpState.phone, otp: otpState.phoneOtp },
        });
      }
      setFlash({ type: 'success', text: `${channel} verification completed.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function createDonorProfile(event) {
    event.preventDefault();
    try {
      const payload = {
        can_donate_blood: donorForm.can_donate_blood,
        organ_types: donorForm.organ_types
          .split(',')
          .map((x) => x.trim())
          .filter(Boolean),
        organ_donation_registered: donorForm.organ_donation_registered,
        preferred_donation_time: donorForm.preferred_donation_time,
        profile: {
          ...donorForm.profile,
          latitude: Number(donorForm.profile.latitude),
          longitude: Number(donorForm.profile.longitude),
        },
      };

      await apiRequest('/donors/register', {
        method: 'POST',
        token: auth.token,
        body: payload,
      });

      setFlash({ type: 'success', text: 'Donor profile created.' });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function toggleAvailability() {
    try {
      const me = await apiRequest('/donors/me', { token: auth.token });
      await apiRequest('/donors/me/availability', {
        method: 'PUT',
        token: auth.token,
        body: { is_available: !me.is_available },
      });
      setFlash({ type: 'success', text: `Availability set to ${!me.is_available}.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function createRecipientProfile(event) {
    event.preventDefault();
    try {
      const payload = {
        ...recipientForm,
        profile: {
          ...recipientForm.profile,
          latitude: Number(recipientForm.profile.latitude),
          longitude: Number(recipientForm.profile.longitude),
        },
      };

      await apiRequest('/recipients/register', {
        method: 'POST',
        token: auth.token,
        body: payload,
      });
      setFlash({ type: 'success', text: 'Recipient profile created.' });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function createRequest(event) {
    event.preventDefault();
    try {
      const payload = {
        request_type: requestForm.request_type,
        blood_group_needed: requestForm.request_type === 'BLOOD' ? requestForm.blood_group_needed : undefined,
        organ_type_needed: requestForm.request_type === 'ORGAN' ? requestForm.organ_type_needed : undefined,
        quantity_needed: Number(requestForm.quantity_needed),
        urgency_level: requestForm.urgency_level,
        needed_by: new Date(requestForm.needed_by).toISOString(),
        hospital_name: requestForm.hospital_name,
        receiving_doctor_name: requestForm.receiving_doctor_name,
        receiving_doctor_phone: requestForm.receiving_doctor_phone,
        hospital_location: {
          latitude: Number(requestForm.hospital_location.latitude),
          longitude: Number(requestForm.hospital_location.longitude),
          address: requestForm.hospital_location.address,
        },
        clinical_notes: requestForm.clinical_notes,
        required_tests: requestForm.required_tests
          .split(',')
          .map((x) => x.trim())
          .filter(Boolean),
        is_public: requestForm.is_public,
      };

      const created = await apiRequest('/requests', {
        method: 'POST',
        token: auth.token,
        body: payload,
      });
      setFlash({ type: 'success', text: `Request created: ${created.request.id}` });
      await loadRequests();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadRequests() {
    try {
      const data = await apiRequest('/requests', { token: auth.token });
      setRequests(data.items || []);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadMatches(requestId) {
    try {
      const data = await apiRequest(`/matches/for-request/${requestId}`, {
        token: auth.token,
      });
      setMatches(data.items || []);
      setFlash({ type: 'success', text: `Loaded ${data.count || 0} matches.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  const loadNotifications = useCallback(async (unreadOnly = false) => {
    if (!auth?.token) {
      return;
    }
    try {
      const data = await apiRequest(`/notifications/me?unread_only=${unreadOnly}`, {
        token: auth.token,
      });
      setNotifications(data.items || []);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }, [auth?.token]);

  useEffect(() => {
    if (!auth?.token) {
      return undefined;
    }

    loadNotifications(true);

    const ws = new WebSocket(wsUrl);
    ws.onmessage = (event) => {
      try {
        const payload = JSON.parse(event.data);
        if (payload.type !== 'INIT_UNREAD') {
          setLiveEvents((prev) => [payload, ...prev].slice(0, 12));
        }
      } catch (err) {
        // Ignore parse failures for non-JSON pings.
      }
    };

    const timer = setInterval(() => {
      loadNotifications(true);
      if (ws.readyState === WebSocket.OPEN) {
        ws.send('ping');
      }
    }, 15000);

    return () => {
      clearInterval(timer);
      ws.close();
    };
  }, [auth?.token, wsUrl, loadNotifications]);

  async function markRead(notificationId) {
    try {
      await apiRequest(`/notifications/${notificationId}/read`, {
        method: 'POST',
        token: auth.token,
      });
      await loadNotifications(true);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadUsers() {
    try {
      const data = await apiRequest('/admin/users?page=1&page_size=50', {
        token: auth.token,
      });
      setUsers(data.items || []);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function verifyUser(userId, verified) {
    const notes = window.prompt('Enter verification note', verified ? 'Approved' : 'Rejected');
    if (!notes) {
      return;
    }
    try {
      await apiRequest(`/admin/verify-user/${userId}`, {
        method: 'POST',
        token: auth.token,
        body: { verified, notes },
      });
      setFlash({ type: 'success', text: `User verification updated for ${userId}.` });
      await loadUsers();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function blockUser(userId) {
    const reason = window.prompt('Block reason', 'Policy violation');
    if (!reason) {
      return;
    }
    try {
      await apiRequest(`/admin/block-user/${userId}`, {
        method: 'POST',
        token: auth.token,
        body: { reason, details: reason },
      });
      setFlash({ type: 'success', text: `Blocked user ${userId}.` });
      await loadUsers();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadAnalytics() {
    try {
      const data = await apiRequest('/admin/analytics', { token: auth.token });
      setAnalytics(data);
      setFlash({ type: 'success', text: 'Analytics loaded.' });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  function logout() {
    setAuth(null);
    setRequests([]);
    setMatches([]);
    setNotifications([]);
    setUsers([]);
    setAnalytics(null);
    setLiveEvents([]);
    setFlash({ type: 'info', text: 'Logged out.' });
  }

  function updateNestedForm(setter, field, value) {
    setter((prev) => ({
      ...prev,
      profile: {
        ...prev.profile,
        [field]: value,
      },
    }));
  }

  return (
    <div className="app-shell">
      <header className="hero">
        <div className="hero-inner">
          <h1>Blood and Organ Donation Portal</h1>
          <p className="subtitle">Real workflows, real matching, real operational controls.</p>
          <div className="status-row">
            <span className="chip">{backendStatus}</span>
            <a href="http://localhost:8002/docs" target="_blank" rel="noreferrer">Open API Docs</a>
          </div>
        </div>
      </header>

      <main className="layout">
        <section className="panel full">
          <div className={`flash ${flash.type}`}>{flash.text}</div>
        </section>

        {!auth && (
          <>
            <section className="panel split">
              <div>
                <h2>Access Portal</h2>
                <div className="tab-row">
                  <button className={authMode === 'login' ? 'active' : ''} onClick={() => setAuthMode('login')}>
                    Login
                  </button>
                  <button className={authMode === 'register' ? 'active' : ''} onClick={() => setAuthMode('register')}>
                    Register
                  </button>
                </div>

                {authMode === 'login' ? (
                  <form onSubmit={handleLogin} className="form-grid">
                    <input
                      placeholder="Email"
                      type="email"
                      value={loginForm.email}
                      onChange={(e) => setLoginForm((p) => ({ ...p, email: e.target.value }))}
                      required
                    />
                    <input
                      placeholder="Password"
                      type="password"
                      value={loginForm.password}
                      onChange={(e) => setLoginForm((p) => ({ ...p, password: e.target.value }))}
                      required
                    />
                    <button type="submit">Login</button>
                  </form>
                ) : (
                  <form onSubmit={handleRegister} className="form-grid">
                    <input placeholder="Email" type="email" value={registerForm.email} onChange={(e) => setRegisterForm((p) => ({ ...p, email: e.target.value }))} required />
                    <input placeholder="Phone" value={registerForm.phone} onChange={(e) => setRegisterForm((p) => ({ ...p, phone: e.target.value }))} required />
                    <input placeholder="Username" value={registerForm.username} onChange={(e) => setRegisterForm((p) => ({ ...p, username: e.target.value }))} required />
                    <input placeholder="Password" type="password" value={registerForm.password} onChange={(e) => setRegisterForm((p) => ({ ...p, password: e.target.value }))} required />
                    <select value={registerForm.role} onChange={(e) => setRegisterForm((p) => ({ ...p, role: e.target.value }))}>
                      <option value="DONOR">DONOR</option>
                      <option value="RECIPIENT">RECIPIENT</option>
                      <option value="ADMIN">ADMIN</option>
                    </select>
                    <button type="submit">Register</button>
                  </form>
                )}
              </div>
            </section>
          </>
        )}

        {auth && (
          <>
            <section className="panel full topbar">
              <div>
                <h2>{auth.user.username}</h2>
                <p>Role: {role}</p>
              </div>
              <div className="tab-row">
                <button className={activeTab === 'dashboard' ? 'active' : ''} onClick={() => setActiveTab('dashboard')}>Dashboard</button>
                <button className={activeTab === 'verify' ? 'active' : ''} onClick={() => setActiveTab('verify')}>Verify</button>
                {role === 'DONOR' && <button className={activeTab === 'donor' ? 'active' : ''} onClick={() => setActiveTab('donor')}>Donor</button>}
                {role === 'RECIPIENT' && <button className={activeTab === 'recipient' ? 'active' : ''} onClick={() => setActiveTab('recipient')}>Recipient</button>}
                {role === 'ADMIN' && <button className={activeTab === 'admin' ? 'active' : ''} onClick={() => setActiveTab('admin')}>Admin</button>}
                <button className={activeTab === 'notifications' ? 'active' : ''} onClick={() => setActiveTab('notifications')}>Notifications</button>
                <button onClick={logout}>Logout</button>
              </div>
            </section>

            {activeTab === 'dashboard' && (
              <section className="panel full">
                <h2>System Dashboard</h2>
                <div className="kpi-grid">
                  <div className="kpi">
                    <h3>Auth</h3>
                    <p>JWT session active</p>
                  </div>
                  <div className="kpi">
                    <h3>Matching</h3>
                    <p>Real-time scoring enabled</p>
                  </div>
                  <div className="kpi">
                    <h3>Notifications</h3>
                    <p>{notifications.length} unread items</p>
                  </div>
                  <div className="kpi">
                    <h3>Live Events</h3>
                    <p>{liveEvents.length} websocket events</p>
                  </div>
                </div>
              </section>
            )}

            {activeTab === 'verify' && (
              <section className="panel split">
                <div>
                  <h2>OTP Verification</h2>
                  <p>Use preview OTP values in development mode.</p>
                  <div className="otp-row">
                    <label>Email OTP</label>
                    <input value={otpState.emailOtp} onChange={(e) => setOtpState((p) => ({ ...p, emailOtp: e.target.value }))} placeholder="6-digit OTP" />
                    <button onClick={() => verifyContact('email')}>Verify Email</button>
                  </div>
                  <div className="otp-row">
                    <label>Phone OTP</label>
                    <input value={otpState.phoneOtp} onChange={(e) => setOtpState((p) => ({ ...p, phoneOtp: e.target.value }))} placeholder="6-digit OTP" />
                    <button onClick={() => verifyContact('phone')}>Verify Phone</button>
                  </div>
                </div>
              </section>
            )}

            {role === 'DONOR' && activeTab === 'donor' && (
              <section className="panel split">
                <div>
                  <h2>Donor Profile Setup</h2>
                  <form onSubmit={createDonorProfile} className="form-grid">
                    <input placeholder="First Name" value={donorForm.profile.first_name} onChange={(e) => updateNestedForm(setDonorForm, 'first_name', e.target.value)} required />
                    <input placeholder="Last Name" value={donorForm.profile.last_name} onChange={(e) => updateNestedForm(setDonorForm, 'last_name', e.target.value)} required />
                    <input placeholder="Address" value={donorForm.profile.address} onChange={(e) => updateNestedForm(setDonorForm, 'address', e.target.value)} required />
                    <input placeholder="City" value={donorForm.profile.city} onChange={(e) => updateNestedForm(setDonorForm, 'city', e.target.value)} required />
                    <input placeholder="State" value={donorForm.profile.state} onChange={(e) => updateNestedForm(setDonorForm, 'state', e.target.value)} required />
                    <input placeholder="Blood Group" value={donorForm.profile.blood_group} onChange={(e) => updateNestedForm(setDonorForm, 'blood_group', e.target.value)} required />
                    <input placeholder="Latitude" value={donorForm.profile.latitude} onChange={(e) => updateNestedForm(setDonorForm, 'latitude', e.target.value)} required />
                    <input placeholder="Longitude" value={donorForm.profile.longitude} onChange={(e) => updateNestedForm(setDonorForm, 'longitude', e.target.value)} required />
                    <input placeholder="Organs (comma separated)" value={donorForm.organ_types} onChange={(e) => setDonorForm((p) => ({ ...p, organ_types: e.target.value }))} />
                    <button type="submit">Create Donor Profile</button>
                  </form>
                  <button className="ghost" onClick={toggleAvailability}>Toggle Availability</button>
                </div>
              </section>
            )}

            {role === 'RECIPIENT' && activeTab === 'recipient' && (
              <section className="panel full">
                <h2>Recipient Operations</h2>
                <div className="split-grid">
                  <form onSubmit={createRecipientProfile} className="form-grid">
                    <h3>Create Recipient Profile</h3>
                    <input placeholder="Primary Disease" value={recipientForm.primary_disease} onChange={(e) => setRecipientForm((p) => ({ ...p, primary_disease: e.target.value }))} required />
                    <input placeholder="Hospital" value={recipientForm.hospital_name} onChange={(e) => setRecipientForm((p) => ({ ...p, hospital_name: e.target.value }))} required />
                    <input placeholder="Doctor Name" value={recipientForm.doctor_name} onChange={(e) => setRecipientForm((p) => ({ ...p, doctor_name: e.target.value }))} required />
                    <input placeholder="Doctor Phone" value={recipientForm.doctor_phone} onChange={(e) => setRecipientForm((p) => ({ ...p, doctor_phone: e.target.value }))} required />
                    <input placeholder="First Name" value={recipientForm.profile.first_name} onChange={(e) => updateNestedForm(setRecipientForm, 'first_name', e.target.value)} required />
                    <input placeholder="Last Name" value={recipientForm.profile.last_name} onChange={(e) => updateNestedForm(setRecipientForm, 'last_name', e.target.value)} required />
                    <input placeholder="Address" value={recipientForm.profile.address} onChange={(e) => updateNestedForm(setRecipientForm, 'address', e.target.value)} required />
                    <input placeholder="City" value={recipientForm.profile.city} onChange={(e) => updateNestedForm(setRecipientForm, 'city', e.target.value)} required />
                    <input placeholder="State" value={recipientForm.profile.state} onChange={(e) => updateNestedForm(setRecipientForm, 'state', e.target.value)} required />
                    <button type="submit">Create Recipient Profile</button>
                  </form>

                  <form onSubmit={createRequest} className="form-grid">
                    <h3>Create Donation Request</h3>
                    <select value={requestForm.request_type} onChange={(e) => setRequestForm((p) => ({ ...p, request_type: e.target.value }))}>
                      <option value="BLOOD">BLOOD</option>
                      <option value="ORGAN">ORGAN</option>
                    </select>
                    {requestForm.request_type === 'BLOOD' ? (
                      <input placeholder="Blood Group" value={requestForm.blood_group_needed} onChange={(e) => setRequestForm((p) => ({ ...p, blood_group_needed: e.target.value }))} required />
                    ) : (
                      <input placeholder="Organ Type" value={requestForm.organ_type_needed} onChange={(e) => setRequestForm((p) => ({ ...p, organ_type_needed: e.target.value }))} required />
                    )}
                    <input placeholder="Quantity" value={requestForm.quantity_needed} onChange={(e) => setRequestForm((p) => ({ ...p, quantity_needed: e.target.value }))} required />
                    <select value={requestForm.urgency_level} onChange={(e) => setRequestForm((p) => ({ ...p, urgency_level: e.target.value }))}>
                      <option value="LOW">LOW</option>
                      <option value="MEDIUM">MEDIUM</option>
                      <option value="CRITICAL">CRITICAL</option>
                    </select>
                    <input type="datetime-local" value={requestForm.needed_by} onChange={(e) => setRequestForm((p) => ({ ...p, needed_by: e.target.value }))} required />
                    <input placeholder="Hospital Name" value={requestForm.hospital_name} onChange={(e) => setRequestForm((p) => ({ ...p, hospital_name: e.target.value }))} required />
                    <input placeholder="Doctor Name" value={requestForm.receiving_doctor_name} onChange={(e) => setRequestForm((p) => ({ ...p, receiving_doctor_name: e.target.value }))} required />
                    <input placeholder="Doctor Phone" value={requestForm.receiving_doctor_phone} onChange={(e) => setRequestForm((p) => ({ ...p, receiving_doctor_phone: e.target.value }))} required />
                    <input placeholder="Hospital Address" value={requestForm.hospital_location.address} onChange={(e) => setRequestForm((p) => ({ ...p, hospital_location: { ...p.hospital_location, address: e.target.value } }))} required />
                    <button type="submit">Create Request and Match</button>
                  </form>
                </div>

                <div className="request-actions">
                  <button onClick={loadRequests}>Load Requests</button>
                </div>

                <div className="list-block">
                  <h3>Requests</h3>
                  {requests.map((item) => (
                    <div key={item.id} className="list-item">
                      <div>
                        <strong>{item.id}</strong> | {item.request_type} | {item.status} | {item.urgency_level}
                      </div>
                      <button onClick={() => loadMatches(item.id)}>Load Matches</button>
                    </div>
                  ))}
                </div>

                <div className="list-block">
                  <h3>Matches</h3>
                  {matches.map((item) => (
                    <div key={item.match_id} className="list-item">
                      <div>
                        {item.match_id} | donor: {item.donor_name} | score: {item.compatibility_score} | distance: {item.distance_km} km
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            )}

            {role === 'ADMIN' && activeTab === 'admin' && (
              <section className="panel full">
                <h2>Admin Control Center</h2>
                <div className="tab-row">
                  <button onClick={loadAnalytics}>Load Analytics</button>
                  <button onClick={loadUsers}>Load Users</button>
                </div>

                {analytics && (
                  <div className="kpi-grid">
                    <div className="kpi"><h3>Total Requests</h3><p>{analytics.metrics.total_requests}</p></div>
                    <div className="kpi"><h3>Total Matches</h3><p>{analytics.metrics.total_matches}</p></div>
                    <div className="kpi"><h3>Success Rate</h3><p>{analytics.metrics.match_success_rate}%</p></div>
                    <div className="kpi"><h3>Total Donors</h3><p>{analytics.metrics.total_donors}</p></div>
                  </div>
                )}

                <div className="list-block">
                  <h3>Users</h3>
                  {users.map((u) => (
                    <div key={u.user_id} className="list-item multi">
                      <div>
                        {u.user_id} | {u.email} | {u.role} | verified: {String(u.id_verified)} | blocked: {String(u.is_blocked)}
                      </div>
                      <div className="tab-row">
                        <button onClick={() => verifyUser(u.user_id, true)}>Verify</button>
                        <button onClick={() => verifyUser(u.user_id, false)}>Reject</button>
                        <button onClick={() => blockUser(u.user_id)}>Block</button>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            )}

            {activeTab === 'notifications' && (
              <section className="panel full">
                <h2>Notifications</h2>
                <div className="tab-row">
                  <button onClick={() => loadNotifications(true)}>Load Unread</button>
                  <button onClick={() => loadNotifications(false)}>Load All</button>
                </div>

                <div className="split-grid">
                  <div className="list-block">
                    <h3>Inbox</h3>
                    {notifications.map((n) => (
                      <div key={n.notification_id} className="list-item multi">
                        <div>
                          {n.notification_type} | {n.title} | read: {String(n.is_read)}
                        </div>
                        {!n.is_read && <button onClick={() => markRead(n.notification_id)}>Mark Read</button>}
                      </div>
                    ))}
                  </div>

                  <div className="list-block">
                    <h3>Live Events (WebSocket)</h3>
                    {liveEvents.map((item, index) => (
                      <div key={`${item.type}-${index}`} className="list-item">
                        <div>{JSON.stringify(item)}</div>
                      </div>
                    ))}
                  </div>
                </div>
              </section>
            )}
          </>
        )}
      </main>
    </div>
  );
}

export default App;
